mapper.select:
/* Payment.selectPaymentById */
SELECT

FROM TB_PAYMENT
WHERE ID = #{id}
  AND DEL_YN = 'N'

/* Payment.selectPaymentByPaymentId */
SELECT

FROM TB_PAYMENT
WHERE PAYMENT_ID = #{paymentId}
  AND DEL_YN = 'N'

/* Payment.selectPaymentDets */
SELECT

FROM TB_PAYMENT_DET
WHERE PAYMENT_ID = #{paymentId}
  AND DEL_YN = 'N'
ORDER BY ID ASC
